	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/schemarepo"
)

// CompactDiffFormatter is a plan formatter that produces a condensed,
// summary-style diff output showing only resource-level changes
// without attribute-level detail.
type CompactDiffFormatter struct{}

// actionDisplayStrings maps action types to their display strings.
var actionDisplayStrings = map[plans.Action]string{
	plans.Create:           "create",
	plans.Update:           "update",
	plans.Delete:           "delete",
	plans.DeleteThenCreate: "replace",
	plans.CreateThenDelete: "replace",
	plans.Read:             "read",
	plans.Forget:           "forget",
	plans.CreateThenForget: "replace",
}

// Format produces a compact, summary-style diff output for a plan.
// It shows one line per resource change: [action] resource_type.name
// Groups changes by action type and shows summary counts at the end.
func (f *CompactDiffFormatter) Format(plan *plans.Plan, schemas *schemarepo.Schemas) string {
	var buf bytes.Buffer

	if plan == nil || plan.Changes == nil {
		return ""
	}

	// Group resources by action
	changes := make(map[plans.Action][]*plans.ResourceInstanceChangeSrc)
	for _, resource := range plan.Changes.Resources {
		// Skip NoOp actions unless we need to show them
		if resource != nil && resource.Action != plans.NoOp {
			changes[resource.Action] = append(changes[resource.Action], resource)
		}
	}

	// Define the order to display action types
	actionOrder := []plans.Action{
		plans.Create,
		plans.Update,
		plans.Delete,
		plans.DeleteThenCreate,
		plans.CreateThenDelete,
		plans.Read,
		plans.Forget,
		plans.CreateThenForget,
	}

	// Track counts for summary
	counts := make(map[plans.Action]int)

	// Display changes grouped by action
	for _, action := range actionOrder {
		resources := changes[action]
		if len(resources) == 0 {
			continue
		}

		// Sort resources by address for consistent output
		sort.Slice(resources, func(i, j int) bool {
			return resources[i].Addr.String() < resources[j].Addr.String()
		})

		actionStr := actionDisplayStrings[action]
		counts[action] = len(resources)

		for _, resource := range resources {
			fmt.Fprintf(&buf, "[%s] %s\n", actionStr, resource.Addr.String())
		}
	}

	// Build summary if there are any changes
	summaryItems := buildSummary(counts)
	if len(summaryItems) > 0 {
		buf.WriteString("\n")
		fmt.Fprintf(&buf, "%s.\n", strings.Join(summaryItems, ", "))
	}

	return buf.String()
}

// buildSummary constructs summary lines from action counts.
func buildSummary(counts map[plans.Action]int) []string {
	summaryItems := make([]string, 0, 7) // Pre-allocate for typical case

	// Define summary items in display order
	summarySpecs := []struct {
		actions []plans.Action
		label   string
	}{
		{
			actions: []plans.Action{plans.Create},
			label:   "Plan: %d to add",
		},
		{
			actions: []plans.Action{plans.Update},
			label:   "%d to change",
		},
		{
			actions: []plans.Action{plans.DeleteThenCreate, plans.CreateThenDelete},
			label:   "%d to replace",
		},
		{
			actions: []plans.Action{plans.Delete},
			label:   "%d to destroy",
		},
		{
			actions: []plans.Action{plans.Read},
			label:   "%d to read",
		},
		{
			actions: []plans.Action{plans.Forget},
			label:   "%d to forget",
		},
		{
			actions: []plans.Action{plans.CreateThenForget},
			label:   "%d to replace and forget",
		},
	}

	for _, spec := range summarySpecs {
		count := 0
		for _, action := range spec.actions {
			count += counts[action]
		}
		if count > 0 {
			summaryItems = append(summaryItems, fmt.Sprintf(spec.label, count))
		}
	}

	return summaryItems
}

